#include <bits/stdc++.h>
using namespace std;
int n;
string a;
char j(string x) {
	char ans;
	int p=x.size();
	if(p==1) {
		if(x=="1") {
			ans='I';
		} else {
			ans='B';
		}
	} else {
		char l=j(x.substr(0,p/2)),r=j(x.substr(p/2));
		if(l==r) {
			ans=l;
		} else {
			ans='F';
		}
	}
	cout<<ans;
	return ans;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>a;
	j(a);
	return 0;
}
